fn calculate_total_file_size(file_sizes: &Vec<u64>) -> Result<u64, String> {
    let mut total: u64 = 0;
    
    for &size in file_sizes {
        total = total.checked_add(size)
            .ok_or_else(|| "Integer overflow: total file size exceeds maximum value".to_string())?;
    }
    
    Ok(total)
}

